-- ============================================================
-- TABLE 1: student
-- ============================================================
CREATE TABLE student (
    student_id        INT          PRIMARY KEY,
    first_name        VARCHAR(30)  NOT NULL,
    last_name         VARCHAR(30)  NOT NULL,
    gender            VARCHAR(10)  NOT NULL,
    degree            VARCHAR(20)  NOT NULL,
    scheme            VARCHAR(20)  NOT NULL,
    passed_out_year   INT          NOT NULL,
    cgpa              DECIMAL(3,1) NOT NULL,
    native_location   VARCHAR(40)  NOT NULL,
    current_location  VARCHAR(40)  NOT NULL,
    placement_branch  VARCHAR(60)  NOT NULL,
    branch_id         INT          NOT NULL
);

-- ============================================================
-- TABLE 2: fees
-- ============================================================
CREATE TABLE fees (
    fee_id        INT  PRIMARY KEY AUTO_INCREMENT,
    student_id    INT          NOT NULL,
    total_fee     INT          NOT NULL,
    discount      INT          NOT NULL,
    amount_paid   INT          NOT NULL,
    balance       INT          NOT NULL,
    payment_mode  VARCHAR(20)  NOT NULL,
    FOREIGN KEY (student_id) REFERENCES student(student_id)
);

-- ============================================================
-- TABLE 3: placement
-- ============================================================
CREATE TABLE placement (
    placement_id      INT  PRIMARY KEY AUTO_INCREMENT,
    student_id        INT          NOT NULL,
    placement_status  VARCHAR(15)  NOT NULL,
    company           VARCHAR(50),
    role              VARCHAR(50),
    ctc_lpa           DECIMAL(4,1),
    FOREIGN KEY (student_id) REFERENCES student(student_id)
);

-- ============================================================
-- TABLE 4: course_completion
-- ============================================================
CREATE TABLE course_completion (
    comp_id            INT  PRIMARY KEY AUTO_INCREMENT,
    student_id         INT          NOT NULL,
    course_name        VARCHAR(50)  NOT NULL,
    mode               VARCHAR(15)  NOT NULL,
    full_completion    INT          NOT NULL,
    partial_completion INT          NOT NULL,
    FOREIGN KEY (student_id) REFERENCES student(student_id)
);

